(function(){
  var page=document.body?document.body.dataset.page:"";
  var data={
    "proof-graph-dashboard":{note:"证明图谱总览展示 candidate 的 proof root、gate root 和当前状态。",wallet:[["Case owner","ChainTrace P0","ok"],["Candidate","RFC-P0-001","ok"],["Execution authority","none in P0","bad"]],proof:[["Evidence root","0xroot...91e","ok"],["Graph root","0xgraph...p0","ok"],["Gate root","0xgate...s3","warn"]],state:[["Proof nodes","31","ok"],["Passed gates","9","ok"],["Blocked gates","2","warn"]],contract:[["Registry write","disabled","bad"],["Disbursement","false","bad"],["Audit link","ready","ok"]]},
    "proof-dependency-map":{note:"依赖图展示 proof DAG，不修改任何上游 proof。",wallet:[["Graph reader","0xSYS...graph","ok"],["Proof owners","multi-role","ok"],["Mutation rights","none","bad"]],proof:[["Candidate hash","0xcand...77f","ok"],["Dependency root","0xdag...001","ok"],["KYB condition","0xcond...signer","warn"]],state:[["Trade facts","passed","ok"],["Identity gate","conditional","warn"],["Settlement gate","blocked","bad"]],contract:[["Append only","yes","ok"],["Original proof edit","disabled","bad"],["State input","ready","ok"]]},
    "case-state-machine":{note:"状态机读取 proof gate，输出 REVIEW_ASSISTANT 和 execution blocked。",wallet:[["State machine","0xSTATE...p0","ok"],["Human approver","required","warn"],["Signer","disabled","bad"]],proof:[["State hash","0xstate...s3","ok"],["Gate checklist","0xcheck...s3","ok"],["Block reason","0xblock...exec","ok"]],state:[["Current state","REVIEW_ASSISTANT","warn"],["Can review","yes","ok"],["Can execute","no","bad"]],contract:[["Wallet signature","disabled","bad"],["Pool tx","disabled","bad"],["Settlement","disabled","bad"]]},
    "proof-graph-result":{note:"结果页把机器状态解释成销售和风控可读语言。",wallet:[["Explanation owner","ChainTrace P0","ok"],["Bank reader","enabled","ok"],["Funder execution","disabled","bad"]],proof:[["Explanation hash","0xexplain...p0","ok"],["Non-exec proof","0xnoexec...p0","ok"],["Audit bundle","0xaudit...001","ok"]],state:[["Review continuation","allowed","ok"],["Funding execution","blocked","bad"],["Disbursement","false","bad"]],contract:[["Registry write","none","bad"],["USDC transfer","none","bad"],["Audit readable","yes","ok"]]}
  };
  var cfg=data[page];
  if(!cfg||document.getElementById("p0-proof-graph-crypto-rail")||document.getElementById("p0-crypto-rail"))return;
  function st(){if(document.getElementById("p0-proof-graph-crypto-rail-style"))return;var s=document.createElement("style");s.id="p0-proof-graph-crypto-rail-style";s.textContent=".proof-crypto{border:1px solid rgba(52,211,153,.28);background:linear-gradient(135deg,rgba(52,211,153,.10),rgba(99,102,241,.08));border-radius:14px;box-shadow:var(--shadow);overflow:hidden}.proof-crypto-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.proof-crypto-card{border:1px solid rgba(159,178,201,.15);background:rgba(7,17,31,.30);border-radius:12px;padding:12px}.proof-crypto-card h3{margin:0 0 10px;font-size:15px}@media(max-width:1200px){.proof-crypto-grid{grid-template-columns:1fr}}";document.head.appendChild(s)}
  function badge(k){return k==="ok"?"ok":k==="warn"?"warn":"bad"}
  function rows(a){return a.map(function(r){return'<li><span><span class="small muted">'+r[0]+'</span><br><span class="strong">'+r[1]+'</span></span><span class="badge '+badge(r[2])+'">'+r[2]+'</span></li>'}).join("")}
  function run(){st();var sec=document.createElement("section");sec.id="p0-proof-graph-crypto-rail";sec.className="section proof-crypto";sec.innerHTML='<div class="section-head"><div><h2>Proof Graph 加密证明轨迹</h2><p class="section-sub">'+cfg.note+'</p></div><span class="badge ok">graph state proof</span></div><div class="content proof-crypto-grid"><div class="proof-crypto-card"><h3>对象 / 权限</h3><ul class="list">'+rows(cfg.wallet)+'</ul></div><div class="proof-crypto-card"><h3>图谱证明</h3><ul class="list">'+rows(cfg.proof)+'</ul></div><div class="proof-crypto-card"><h3>状态输出</h3><ul class="list">'+rows(cfg.state)+'</ul></div><div class="proof-crypto-card"><h3>执行边界</h3><ul class="list">'+rows(cfg.contract)+'</ul></div></div>';var rail=document.getElementById("p0-proof-graph-rail");if(rail&&rail.parentNode){rail.parentNode.insertBefore(sec,rail.nextSibling);return}var hero=document.querySelector(".main .hero");if(hero&&hero.parentNode)hero.parentNode.insertBefore(sec,hero.nextSibling);else document.querySelector(".main")?.prepend(sec)}
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
})();